import type { CrossplaneServiceStatusPhase } from "@workspace/crossplane/lib/status";

/** Service phase; aligns with Crossplane/Kubernetes-style statuses and theme tones. */
export type ContainerNodeStatusTone = CrossplaneServiceStatusPhase;

/** Display state for a container node (passed into Root as `states`). */
export interface ContainerNodeStates {
  cpuPercent?: number;
  image: string;
  kind?: string;
  memoryPercent?: number;
  name: string;
  replicas?: number;
  status?: {
    label: string;
    tone: ContainerNodeStatusTone;
  };
}

/** Optional handlers wired from the default header menu. */
export interface ContainerNodeActions {
  onDelete?: () => void;
  onOpenShell?: () => void;
  onRestart?: () => void;
  /** Fired from the Scale dialog when the user commits a replica count (pointer release). */
  onScale?: (nextReplicas: number) => void;
  onViewLogs?: () => void;
}

export interface ContainerNodeValue {
  actions: ContainerNodeActions;
  states: ContainerNodeStates;
}

"use client";

import { createContext, type ReactNode, useContext, useMemo } from "react";

import type {
  ContainerNodeActions,
  ContainerNodeStates,
  ContainerNodeValue,
} from "./container-node.types";

export const ContainerNodeContext = createContext<ContainerNodeValue | null>(
  null
);

export function useContainerNode(): ContainerNodeValue {
  const value = useContext(ContainerNodeContext);
  if (!value) {
    throw new Error(
      "ContainerNode: useContainerNode must be used within ContainerNode.Root"
    );
  }
  return value;
}

export function ContainerNodeRoot({
  actions = {},
  children,
  states,
}: {
  actions?: ContainerNodeActions;
  children?: ReactNode;
  states: ContainerNodeStates;
}) {
  const value = useMemo(
    (): ContainerNodeValue => ({ actions, states }),
    [actions, states]
  );

  return (
    <ContainerNodeContext.Provider value={value}>
      {children}
    </ContainerNodeContext.Provider>
  );
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import type { ComponentProps } from "react";

export function ContainerNodeShell({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "flex min-h-0 min-w-0 flex-col overflow-hidden rounded-xl border border-border bg-background-secondary text-card-foreground text-xs shadow-xs",
        className
      )}
      {...props}
    />
  );
}

export function ContainerNodeHeader({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "flex shrink-0 flex-row flex-wrap items-center gap-2 border-border/60 border-b px-3 py-2",
        className
      )}
      {...props}
    />
  );
}

export function ContainerNodeContent({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn("flex min-h-0 flex-1 flex-col px-3 py-2", className)}
      {...props}
    />
  );
}

export function ContainerNodeFooter({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "flex min-w-0 shrink-0 flex-row items-center justify-between gap-3 border-border/60 border-t px-3 py-2",
        className
      )}
      {...props}
    />
  );
}

/** Cluster CPU / memory (or other) resource rows and pin them to the end of the footer (opposite status). */
export function ContainerNodeResourceGroup({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "flex min-w-0 shrink-0 items-center justify-end gap-3 whitespace-nowrap",
        className
      )}
      {...props}
    />
  );
}

"use client";

import { ThreeDViewIcon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import {
  getStatusIndicatorClass,
  getStatusTextClass,
} from "@workspace/crossplane/lib/status";
import { FlashNumber } from "@workspace/ui/components/flash-number/flash-number";
import { cn } from "@workspace/ui/lib/utils";
import type { LucideIcon } from "lucide-react";
import { Layers } from "lucide-react";
import { type ComponentProps, useContext } from "react";

import {
  ContainerNodeContext,
  useContainerNode,
} from "./container-node.context";
import type { ContainerNodeStatusTone } from "./container-node.types";

export function ContainerNodeTitle({
  className,
  children,
  ...props
}: ComponentProps<"div">) {
  const ctx = useContext(ContainerNodeContext);
  const content = children ?? ctx?.states.name;
  if (content == null) {
    return null;
  }
  return (
    <div
      className={cn(
        "min-w-0 max-w-full truncate font-medium text-xs leading-tight",
        className
      )}
      {...props}
    >
      {content}
    </div>
  );
}

const DEFAULT_KIND = "Container";

export function ContainerNodeKind({
  className,
  children,
  ...props
}: ComponentProps<"div">) {
  const ctx = useContext(ContainerNodeContext);
  const content = children ?? (ctx ? (ctx.states.kind ?? DEFAULT_KIND) : null);
  if (content == null) {
    return null;
  }
  return (
    <div
      className={cn(
        "min-w-0 max-w-full truncate text-[10px] text-muted-foreground",
        className
      )}
      {...props}
    >
      {content}
    </div>
  );
}

export function ContainerNodeStatus({
  className,
  label: labelProp,
  tone: toneProp,
}: {
  className?: string;
  label?: string;
  tone?: ContainerNodeStatusTone;
}) {
  const ctx = useContext(ContainerNodeContext);
  const label = labelProp ?? ctx?.states.status?.label ?? "unknown";
  const tone = toneProp ?? ctx?.states.status?.tone;

  if (tone == null) {
    return (
      <div
        className={cn("flex min-w-0 flex-1 items-center gap-1.5", className)}
      >
        <span aria-hidden className="relative flex size-2 shrink-0">
          <span className="relative inline-flex size-2 shrink-0 rounded-[2px] bg-muted" />
        </span>
        <span className="truncate whitespace-nowrap font-medium text-muted-foreground text-xs">
          {label}
        </span>
      </div>
    );
  }

  return (
    <div className={cn("flex min-w-0 flex-1 items-center gap-1.5", className)}>
      <span aria-hidden className="relative flex size-2 shrink-0">
        <span
          className={cn(
            "absolute inset-0 inline-flex animate-ping rounded-[2px] opacity-75",
            getStatusIndicatorClass(tone)
          )}
        />
        <span
          className={cn(
            "relative inline-flex size-2 shrink-0 rounded-[2px]",
            getStatusIndicatorClass(tone)
          )}
        />
      </span>
      <span
        className={cn(
          "truncate whitespace-nowrap font-medium text-xs",
          getStatusTextClass(tone)
        )}
      >
        {label}
      </span>
    </div>
  );
}

export function ContainerNodeResource({
  className,
  icon: Icon,
  percent,
}: {
  className?: string;
  icon: LucideIcon;
  percent?: number;
}) {
  if (percent == null || !Number.isFinite(percent)) {
    return (
      <div className={cn("flex shrink-0 items-center gap-1", className)}>
        <Icon aria-hidden className="size-3 shrink-0 text-muted-foreground" />
        <span className="whitespace-nowrap tabular-nums">...</span>
      </div>
    );
  }
  return (
    <FlashNumber
      className={cn("text-xs", className)}
      icon={Icon}
      maxDecimals={1}
      value={percent}
    />
  );
}

/** Replica count from `states.replicas`, shown with a layers icon. */
export function ContainerNodeReplicas({ className }: { className?: string }) {
  const {
    states: { replicas },
  } = useContainerNode();
  return (
    <div className={cn("flex shrink-0 items-center gap-1", className)}>
      <Layers aria-hidden className="size-3 shrink-0 text-muted-foreground" />
      <span className="whitespace-nowrap text-xs tabular-nums">
        {replicas == null ? "..." : replicas}
      </span>
    </div>
  );
}

export function ContainerNodeIconPlaceholder({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "flex size-7 shrink-0 items-center justify-center rounded bg-muted ring-1 ring-foreground/10",
        className
      )}
      {...props}
    >
      <HugeiconsIcon
        aria-hidden
        className="text-muted-foreground"
        icon={ThreeDViewIcon}
        size={24}
        strokeWidth={2}
      />
    </div>
  );
}

/** Read-only Docker / OCI image reference from context `states.image`. */
export function ContainerNodeImage({
  className,
  label = "Image",
  labelClassName,
}: {
  className?: string;
  label?: string;
  labelClassName?: string;
}) {
  const {
    states: { image },
  } = useContainerNode();
  const display = image.trim() === "" ? "—" : image;
  return (
    <div
      className={cn(
        "flex min-h-0 min-w-0 flex-1 flex-row items-start gap-2",
        className
      )}
    >
      <span
        className={cn(
          "shrink-0 pt-0.5 font-medium text-[10px] text-muted-foreground uppercase tracking-wide",
          labelClassName
        )}
      >
        {label}:
      </span>
      <p
        className="min-w-0 flex-1 truncate font-mono text-[11px] text-foreground leading-snug"
        title={display === "—" ? undefined : display}
      >
        {display}
      </p>
    </div>
  );
}

"use client";

import { Button } from "@workspace/ui/components/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@workspace/ui/components/dropdown-menu";
import { cn } from "@workspace/ui/lib/utils";
import { MoreHorizontal } from "lucide-react";
import { type ReactNode, type SyntheticEvent, useState } from "react";

import { useContainerNode } from "./container-node.context";
import { ContainerNodeDeleteDialog } from "./container-node.delete-dialog";
import { ContainerNodeScaleDialog } from "./container-node.scale-dialog";

/**
 * React Flow utility classes — required for controls inside custom nodes so pointer
 * events are not consumed for drag/pan. Prefer these over `stopPropagation` on the
 * trigger, which can break Base UI menu triggers. See:
 * https://reactflow.dev/learn/customization/utility-classes
 */
const RF_MENU_SURFACE_CLASS = "nodrag nopan";

function stopCanvasNodeClick(e: SyntheticEvent) {
  e.stopPropagation();
}

export function ContainerNodeHeaderMenu({ menu }: { menu?: ReactNode }) {
  const { actions, states } = useContainerNode();
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [scaleDialogOpen, setScaleDialogOpen] = useState(false);

  if (menu != null) {
    return (
      <DropdownMenu>
        <DropdownMenuTrigger
          render={
            <Button
              aria-label="Open menu"
              className={cn(RF_MENU_SURFACE_CLASS, "size-7 shrink-0")}
              onClick={stopCanvasNodeClick}
              size="icon"
              variant="ghost"
            />
          }
        >
          <MoreHorizontal className="size-3.5" />
        </DropdownMenuTrigger>
        <DropdownMenuContent
          align="start"
          className={cn(RF_MENU_SURFACE_CLASS, "rounded-xl")}
        >
          {menu}
        </DropdownMenuContent>
      </DropdownMenu>
    );
  }

  return (
    <>
      <DropdownMenu>
        <DropdownMenuTrigger
          render={
            <Button
              aria-label="Open menu"
              className={cn(RF_MENU_SURFACE_CLASS, "size-7 shrink-0")}
              onClick={stopCanvasNodeClick}
              size="icon"
              variant="ghost"
            />
          }
        >
          <MoreHorizontal className="size-3.5" />
        </DropdownMenuTrigger>
        <DropdownMenuContent
          align="start"
          className={cn(RF_MENU_SURFACE_CLASS, "rounded-xl")}
        >
          <DropdownMenuItem
            className="rounded-xl text-xs"
            onClick={() => setScaleDialogOpen(true)}
          >
            Scale
          </DropdownMenuItem>
          <DropdownMenuItem
            className="rounded-xl text-xs"
            onClick={actions.onRestart}
          >
            Restart
          </DropdownMenuItem>
          <DropdownMenuItem
            className="rounded-xl text-xs"
            onClick={actions.onViewLogs}
          >
            View logs
          </DropdownMenuItem>
          <DropdownMenuItem
            className="rounded-xl text-xs"
            onClick={actions.onOpenShell}
          >
            Open shell
          </DropdownMenuItem>
          <DropdownMenuItem
            className="rounded-xl text-xs"
            onClick={() => setDeleteDialogOpen(true)}
            variant="destructive"
          >
            Delete
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>
      <ContainerNodeScaleDialog
        onOpenChange={setScaleDialogOpen}
        onScale={actions.onScale}
        open={scaleDialogOpen}
        replicas={states.replicas ?? 0}
      />
      <ContainerNodeDeleteDialog
        kind={states.kind}
        name={states.name}
        onConfirmDelete={actions.onDelete}
        onOpenChange={setDeleteDialogOpen}
        open={deleteDialogOpen}
      />
    </>
  );
}

"use client";

import { Cpu, MemoryStick } from "lucide-react";
import type { ComponentProps } from "react";

import { useContainerNode } from "./container-node.context";
import { ContainerNodeHeaderMenu } from "./container-node.header-menu";
import {
  ContainerNodeContent,
  ContainerNodeFooter,
  ContainerNodeHeader,
  ContainerNodeResourceGroup,
  ContainerNodeShell,
} from "./container-node.layout";
import {
  ContainerNodeIconPlaceholder,
  ContainerNodeImage,
  ContainerNodeKind,
  ContainerNodeReplicas,
  ContainerNodeResource,
  ContainerNodeStatus,
  ContainerNodeTitle,
} from "./container-node.primitives";

/** First composed layout: shell + header / image / footer using primitives + context. */
export function ContainerNodeVariant0({
  className,
}: ComponentProps<typeof ContainerNodeShell>) {
  const { states } = useContainerNode();

  return (
    <ContainerNodeShell className={className}>
      <ContainerNodeHeader>
        <div className="flex min-h-0 min-w-0 flex-1 items-center gap-2">
          <ContainerNodeIconPlaceholder />
          <div className="flex min-w-0 flex-1 flex-col gap-0.5">
            <ContainerNodeTitle />
            <ContainerNodeKind />
          </div>
        </div>
        <ContainerNodeHeaderMenu />
      </ContainerNodeHeader>
      <ContainerNodeContent>
        <ContainerNodeImage />
      </ContainerNodeContent>
      <ContainerNodeFooter>
        <ContainerNodeStatus />
        <ContainerNodeResourceGroup>
          <ContainerNodeResource icon={Cpu} percent={states.cpuPercent} />
          <ContainerNodeResource
            icon={MemoryStick}
            percent={states.memoryPercent}
          />
          <ContainerNodeReplicas />
        </ContainerNodeResourceGroup>
      </ContainerNodeFooter>
    </ContainerNodeShell>
  );
}

"use client";

import {
  ContainerNodeContext,
  ContainerNodeRoot,
  useContainerNode as useContainerNodeBound,
} from "./container-node.context";
import {
  ContainerNodeDeleteDialog,
  ContainerNodeDeleteDialogPanel,
} from "./container-node.delete-dialog";
import { ContainerNodeHeaderMenu } from "./container-node.header-menu";
import {
  ContainerNodeContent,
  ContainerNodeFooter,
  ContainerNodeHeader,
  ContainerNodeResourceGroup,
  ContainerNodeShell,
} from "./container-node.layout";
import {
  ContainerNodeIconPlaceholder,
  ContainerNodeImage,
  ContainerNodeKind,
  ContainerNodeReplicas,
  ContainerNodeResource,
  ContainerNodeStatus,
  ContainerNodeTitle,
} from "./container-node.primitives";
import {
  ContainerNodeScaleDialog,
  ContainerNodeScaleDialogPanel,
} from "./container-node.scale-dialog";
import { ContainerNodeVariant0 } from "./container-node.variant0";

// biome-ignore lint/performance/noBarrelFile: compound hook re-export for `import { useContainerNode }`
export { useContainerNode } from "./container-node.context";
export type {
  ContainerNodeActions,
  ContainerNodeStates,
  ContainerNodeStatusTone,
  ContainerNodeValue,
} from "./container-node.types";

export const ContainerNode = Object.assign(ContainerNodeShell, {
  Content: ContainerNodeContent,
  Context: ContainerNodeContext,
  DeleteDialog: ContainerNodeDeleteDialog,
  DeleteDialogPanel: ContainerNodeDeleteDialogPanel,
  Footer: ContainerNodeFooter,
  Header: ContainerNodeHeader,
  ResourceGroup: ContainerNodeResourceGroup,
  HeaderMenu: ContainerNodeHeaderMenu,
  IconPlaceholder: ContainerNodeIconPlaceholder,
  Image: ContainerNodeImage,
  Kind: ContainerNodeKind,
  Replicas: ContainerNodeReplicas,
  Resource: ContainerNodeResource,
  Root: ContainerNodeRoot,
  ScaleDialog: ContainerNodeScaleDialog,
  ScaleDialogPanel: ContainerNodeScaleDialogPanel,
  Shell: ContainerNodeShell,
  Status: ContainerNodeStatus,
  Title: ContainerNodeTitle,
  Variant0: ContainerNodeVariant0,
  useContainerNode: useContainerNodeBound,
});

const dn = (c: object, name: string) => {
  (c as { displayName?: string }).displayName = name;
};
dn(ContainerNodeRoot, "ContainerNode.Root");
dn(ContainerNodeVariant0, "ContainerNode.Variant0");
dn(ContainerNodeShell, "ContainerNode.Shell");
dn(ContainerNodeHeader, "ContainerNode.Header");
dn(ContainerNodeContent, "ContainerNode.Content");
dn(ContainerNodeFooter, "ContainerNode.Footer");
dn(ContainerNodeResourceGroup, "ContainerNode.ResourceGroup");
dn(ContainerNodeReplicas, "ContainerNode.Replicas");

export type {
  ContainerNodeDeleteDialogPanelProps,
  ContainerNodeDeleteDialogProps,
} from "./container-node.delete-dialog";
export type {
  ContainerNodeScaleDialogPanelProps,
  ContainerNodeScaleDialogProps,
} from "./container-node.scale-dialog";

"use client";

import {
  AlertDialog,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@workspace/ui/components/alert-dialog";
import { Button } from "@workspace/ui/components/button";
import { cn } from "@workspace/ui/lib/utils";

const DELETE_TITLE = "Delete workload?";

function WorkloadDeleteCopy({ kind, name }: { kind?: string; name: string }) {
  const k = kind?.trim();
  return (
    <>
      This will delete{" "}
      <span className="font-medium text-foreground">{name}</span>
      {k != null && k !== "" ? (
        <>
          {" "}
          (<span className="font-mono">{k}</span>)
        </>
      ) : null}{" "}
      from the cluster. This cannot be undone.
    </>
  );
}

export interface ContainerNodeDeleteDialogPanelProps {
  className?: string;
  kind?: string;
  name: string;
  onCancel: () => void;
  onConfirmDelete?: () => void;
}

/** In-flow panel (no portal). Use in previews or custom layouts. */
export function ContainerNodeDeleteDialogPanel({
  className,
  kind,
  name,
  onCancel,
  onConfirmDelete,
}: ContainerNodeDeleteDialogPanelProps) {
  return (
    <div
      className={cn(
        "grid w-full max-w-md gap-6 rounded-xl bg-background p-6 text-sm ring-1 ring-foreground/10",
        className
      )}
    >
      <div className="flex flex-col gap-2">
        <h3 className="font-medium leading-none">{DELETE_TITLE}</h3>
        <p className="text-balance text-muted-foreground text-sm md:text-pretty">
          <WorkloadDeleteCopy kind={kind} name={name} />
        </p>
      </div>
      <div className="flex flex-col-reverse gap-2 sm:flex-row sm:justify-end">
        <Button onClick={onCancel} variant="outline">
          Cancel
        </Button>
        <Button
          className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
          onClick={() => {
            onConfirmDelete?.();
          }}
          type="button"
          variant="destructive"
        >
          Delete
        </Button>
      </div>
    </div>
  );
}

ContainerNodeDeleteDialogPanel.displayName = "ContainerNodeDeleteDialogPanel";

export interface ContainerNodeDeleteDialogProps {
  /** Shown in monospace after the name (e.g. `AP`, `DB`), like project resource id. */
  kind?: string;
  /** Workload display name shown in the copy. */
  name: string;
  onConfirmDelete?: () => void;
  onOpenChange: (open: boolean) => void;
  open: boolean;
}

export function ContainerNodeDeleteDialog({
  open,
  onOpenChange,
  kind,
  name,
  onConfirmDelete,
}: ContainerNodeDeleteDialogProps) {
  return (
    <AlertDialog onOpenChange={onOpenChange} open={open}>
      <AlertDialogContent data-slot="container-node-delete-dialog">
        <AlertDialogHeader>
          <AlertDialogTitle>{DELETE_TITLE}</AlertDialogTitle>
          <AlertDialogDescription>
            <WorkloadDeleteCopy kind={kind} name={name} />
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <Button
            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            onClick={() => {
              onConfirmDelete?.();
              onOpenChange(false);
            }}
            type="button"
            variant="destructive"
          >
            Delete
          </Button>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

ContainerNodeDeleteDialog.displayName = "ContainerNodeDeleteDialog";

"use client";

import { Dialog, DialogContent } from "@workspace/ui/components/dialog";
import { ScaleSlider } from "@workspace/ui/components/scale-slider/scale-slider";
import { cn } from "@workspace/ui/lib/utils";
import { useEffect, useMemo, useState } from "react";

export interface ContainerNodeScaleDialogPanelProps {
  className?: string;
  draft: number;
  max: number;
  onDraftChange: (next: number) => void;
  onScale?: (nextReplicas: number) => void;
}

/** In-flow scale controls (no portal). Use in previews or custom layouts. */
export function ContainerNodeScaleDialogPanel({
  className,
  draft,
  max,
  onDraftChange,
  onScale,
}: ContainerNodeScaleDialogPanelProps) {
  return (
    <div
      className={cn("flex flex-col items-center justify-center p-6", className)}
    >
      <ScaleSlider.Root
        max={max}
        maxDecimals={0}
        min={0}
        onValueChange={onDraftChange}
        step={1}
        value={draft}
        valueDisplay="number"
      >
        <ScaleSlider.Stack className="w-full max-w-xs">
          <ScaleSlider.Header>
            <ScaleSlider.Label>Replicas</ScaleSlider.Label>
            <ScaleSlider.Value />
          </ScaleSlider.Header>
          <ScaleSlider.Control
            onValueCommit={(vals) => {
              const n = vals[0];
              if (n !== undefined) {
                onScale?.(n);
              }
            }}
          >
            <ScaleSlider.Track>
              <ScaleSlider.Range />
            </ScaleSlider.Track>
            <ScaleSlider.Thumb />
          </ScaleSlider.Control>
        </ScaleSlider.Stack>
      </ScaleSlider.Root>
    </div>
  );
}

ContainerNodeScaleDialogPanel.displayName = "ContainerNodeScaleDialogPanel";

export interface ContainerNodeScaleDialogProps {
  /** Upper bound for the slider (defaults to at least 20 and the current draft). */
  maxReplicas?: number;
  onOpenChange: (open: boolean) => void;
  /** Called when the user releases the thumb with a new replica count. */
  onScale?: (nextReplicas: number) => void;
  open: boolean;
  /** Current replica count when the dialog opens or `replicas` updates while open. */
  replicas: number;
}

export function ContainerNodeScaleDialog({
  open,
  onOpenChange,
  replicas,
  onScale,
  maxReplicas: maxReplicasProp,
}: ContainerNodeScaleDialogProps) {
  const [draft, setDraft] = useState(replicas);

  useEffect(() => {
    if (open) {
      setDraft(replicas);
    }
  }, [open, replicas]);

  const scaleMax = useMemo(
    () => maxReplicasProp ?? Math.max(20, replicas, draft, 1),
    [draft, maxReplicasProp, replicas]
  );

  return (
    <Dialog onOpenChange={onOpenChange} open={open}>
      <DialogContent
        className="gap-0 p-0 sm:max-w-sm"
        closeButtonClassName="top-2 right-2 size-5"
      >
        <ContainerNodeScaleDialogPanel
          draft={draft}
          max={scaleMax}
          onDraftChange={setDraft}
          onScale={onScale}
        />
      </DialogContent>
    </Dialog>
  );
}

ContainerNodeScaleDialog.displayName = "ContainerNodeScaleDialog";

import type { CrossplaneServiceStatusPhase } from "@workspace/crossplane/lib/status";

/** Service phase; aligns with Crossplane/Kubernetes-style statuses and theme tones. */
export type ContainerNodeStatusTone = CrossplaneServiceStatusPhase;

/** Aggregated node data for canvas/graph payloads; compose v1 UI with explicit per-field props. */
export interface ContainerNodeStates {
  cpuPercent?: number;
  image: string;
  kind?: string;
  memoryPercent?: number;
  name: string;
  /**
   * Kubernetes `metadata.namespace` (or list query fallback) for **AP** lifecycle
   * API calls; omit when unknown or for non-cluster nodes.
   */
  namespace?: string;
  replicas?: number;
  status?: {
    label: string;
    tone: ContainerNodeStatusTone;
  };
  /**
   * Kubernetes `metadata.uid` when this payload was built from a live
   * resource; stable across renames. Omit for static / storybook-only nodes.
   */
  uid?: string;
}

/** Optional handlers for host-composed header / toolbar controls. */
export interface ContainerNodeActions {
  onDelete?: () => void;
  onOpenShell?: () => void;
  onPause?: () => void;
  onRestart?: () => void;
  /** Fired from the Scale dialog when the user commits a replica count (pointer release). */
  onScale?: (nextReplicas: number) => void;
  onStart?: () => void;
  /** Icon toolbar (v1): activity / metrics. */
  onViewActivity?: () => void;
  /** Icon toolbar (v1): schedule / events. */
  onViewCalendar?: () => void;
  onViewLogs?: () => void;
}

import type { ContainerNodeStatusTone } from "./container-node.types";

const FAILED_PHASES = new Set<ContainerNodeStatusTone>([
  "failed",
  "error",
  "deleting",
  "unavailable",
  "degraded",
]);

const HEALTHY_RUNNING_PHASES = new Set<ContainerNodeStatusTone>([
  "running",
  "succeeded",
  "complete",
  "available",
  "bound",
  "ready",
]);

const PAUSED_STOPPED_PHASES = new Set<ContainerNodeStatusTone>([
  "paused",
  "stopped",
  "shutdown",
]);

/**
 * Which lifecycle header-menu rows to show from workload `status.tone`.
 * Delete is always available when composed.
 * - Failed-like: Restart + Delete only.
 * - Healthy / running-like: Pause + Restart + Delete (no Start).
 * - Paused / stopped: Start + Restart + Delete (no Pause).
 * - Otherwise (e.g. pending): Start + Pause + Restart.
 */
export function containerNodeLifecycleMenuVisibility(
  tone: ContainerNodeStatusTone | undefined
): {
  showPause: boolean;
  showRestart: boolean;
  showStart: boolean;
} {
  if (tone != null && FAILED_PHASES.has(tone)) {
    return { showStart: false, showPause: false, showRestart: true };
  }
  if (tone != null && HEALTHY_RUNNING_PHASES.has(tone)) {
    return { showStart: false, showPause: true, showRestart: true };
  }
  if (tone != null && PAUSED_STOPPED_PHASES.has(tone)) {
    return { showStart: true, showPause: false, showRestart: true };
  }
  return { showStart: true, showPause: true, showRestart: true };
}

